from ExtractiveSummarization.extrarizer import extrarizer

text_to_summarize = "ПФЛ выступила с заявлением по поводу ситуации с завершением сезона-2019/20. Лига отмечает, что доиграть сезон, прерванный из-за пандемии короновируса, проблематично. Клубы в текущий и ближайший период не могут проводить тренировочные мероприятия, существует неопределённость по срокам возобновления соревнований, кроме того, у клубов возникнут дополнительные организационные и финансовые издержки в случае продления паузы. Клубы ПФЛ в ходе видеоконференци в апреле отметили, что для проведения оставшихся игр им потребуется период в 1,5 месяца, а также не меньше трех недель на тренировки для набора формы. Совет и администрация ПФЛ призвали объявить сезон завершённым и предоставить право выхода в ФНЛ тем клубам, которые имеют лучшие спортивные показатели и соответствуют необходимым требованиям. Ранее большинство клубов в ФНЛ также проголосовали за досрочное завершение сезона."

print(extrarizer.summarize(text_to_summarize, 2))